const theme = $('Receive Bookmark Request').item.json.body.theme;
const imageUrl = $('Artist Generate').item.json.image_url;
const frontImagePath = $('Compositor Render').item.json.front_image_path || imageUrl;
const backImagePath = $('Compositor Render').item.json.back_image_path || null;
const wa = $('Write & Approve').item.json;
const listing = wa.listing;
const review = wa.review;
const attempts = wa.attempts;
const targetReached = wa.target_reached;
const consultationTurns = wa.consultation || [];
const productId = $('Save Product').item.json.product_id;
const taskId = $('Build Artist Payload').item.json.task_id;

const overall = review.overall || 0;
const recommendation = review.recommendation || 'No recommendation';

let badge;
if (overall >= 9 && targetReached) {
  badge = overall >= 9.5 ? 'EXCEPTIONAL' : 'APPROVED';
} else {
  badge = 'BEST EFFORT';
}

const scores = review.scores || {};
const scoreLines = Object.entries(scores).map(([k, v]) =>
  `  ${k}: ${v.score}/10 — ${v.note}`
).join('\n');

const tags = (listing.tags || []).slice(0, 8).join(', ');

const attemptsNote = attempts === 1
  ? 'Approved on first attempt.'
  : `Reached score after ${attempts} revision${attempts > 1 ? 's' : ''}.`;

const consultLines = consultationTurns.length > 0
  ? consultationTurns.flatMap(t => [
      `[${t.agent} — ${t.role}]`,
      t.message,
      '',
    ])
  : ['(No consultation recorded)'];

const summary = [
  `=== BOOKMARK PIPELINE COMPLETE — ${badge} ===`,
  '',
  `Task ID   : ${taskId}`,
  `Product ID: ${productId}`,
  `Theme     : ${theme}`,
  `Score     : ${overall}/10  |  ${attemptsNote}`,
  '',
  '--- AGENT CONSULTATION ---',
  ...consultLines,
  '--- LISTING ---',
  `Title     : ${listing.title || '—'}`,
  `Quote     : ${listing.bookmark_quote || '—'}`,
  `Price     : ${listing.price_note || '—'}`,
  `Tags      : ${tags}`,
  '',
  '--- IMAGE ---',
  `Source    : ${imageUrl}`,
  `Front     : ${frontImagePath}`,
  `Back      : ${backImagePath || '—'}`,
  '',
  '--- REVIEW ---',
  `Overall   : ${overall}/10`,
  `Decision  : ${recommendation}`,
  '',
  'Principle scores:',
  scoreLines,
  '',
  targetReached
    ? 'Next step: Review front + back images, then post to Etsy.'
    : `Note: Could not reach 9.0 after ${attempts} attempts (${overall}/10). Listing saved — review manually before posting.`,
].join('\n');

return [{
  json: {
    task_id: taskId,
    product_id: productId,
    theme: theme,
    image_url: imageUrl,
    front_image_path: frontImagePath,
    back_image_path: backImagePath,
    bookmark_quote: listing.bookmark_quote || null,
    listing_title: listing.title,
    listing_tags: listing.tags,
    listing_description: listing.description,
    price_note: listing.price_note,
    review_overall: overall,
    review_passed: review.passed,
    review_recommendation: recommendation,
    badge: badge,
    attempts: attempts,
    target_reached: targetReached,
    consultation: consultationTurns,
    summary: summary,
  }
}];
